from flask import Flask, redirect, request, session
import requests
import json
import base64

app = Flask(__name__)
app.secret_key = 'your_secret_key'

client_id = 'your_client_id'
client_secret = 'your_client_secret'
redirect_uri = 'http://your_callback_url'

provider_authorize_url = 'http://provider_authorize_endpoint'
token_url = 'http://provider_token_endpoint'
userinfo_url = 'http://provider_userinfo_endpoint'

@app.route('/')
def login():
    return redirect(provider_authorize_url + '?client_id=' + client_id + '&redirect_uri=' + redirect_uri + '&response_type=code')

@app.route('/callback')
def callback():
    code = request.args.get('code')
    token_response = requests.post(token_url, data={'code': code, 'client_id': client_id, 'client_secret': client_secret, 'redirect_uri': redirect_uri, 'grant_type': 'authorization_code'})
    token_data = token_response.json()
    
    id_token = token_data['id_token']
    id_token_parts = id_token.split('.')
    id_token_payload = json.loads(base64.b64decode(id_token_parts[1] + '==').decode('utf-8'))
    
    session['user_info'] = id_token_payload
    return redirect('/profile')

@app.route('/profile')
def profile():
    user_info = session.get('user_info')
    return user_info

if __name__ == '__main__':
    app.run()